example.code:
// 接口级别：所有方法均允许任何状态码
[HttpClientApi]
[AllowAnyStatusCode]
public interface IUserApi
{
    [Get("/api/users/{id}")]
    Task<Response<User>> GetUserAsync(int id);
}

// 方法级别：仅该方法允许任何状态码
[HttpClientApi]
public interface IUserApi
{
    [AllowAnyStatusCode]
    [Get("/api/users/{id}")]
    Task<Response<User>> GetUserAsync(int id);

    [Post("/api/users")]
    Task<User> CreateUserAsync([Body] User user);
}

[HttpClientApi(HttpClient = "IEnhancedHttpClient")]
[BasePath("api/v1")]
public interface IUserApi
{
    [Get("users/{id}")]  // 实际路径: /api/v1/users/{id}
    Task<User> GetUserAsync([Path] int id);

    [Get("/admin/users")]  // 以 / 开头，忽略 BasePath，实际路径: /admin/users
    Task<List<User>> GetAllUsersAsync();
}

// JSON 序列化（默认）
[Post("/api/users")]
Task<User> CreateUserAsync([Body] User user);

// 自定义内容类型
[Post("/api/data")]
Task SendDataAsync([Body("application/xml")] string xmlData);

// 原始字符串（不序列化）
[Post("/api/text")]
Task SendTextAsync([Body(RawString = true)] string plainText);

// 加密请求体
[Post("/api/secure")]
Task SendSecureDataAsync([Body(EnableEncrypt = true)] SecureData data);

// 基本缓存（5分钟）
[Get("/api/users")]
[Cache(300)]
Task<List<User>> GetUsersAsync();

// 自定义缓存键和滑动过期
[Get("/api/users/{id}")]
[Cache(600, CacheKeyTemplate = "user_{id}", UseSlidingExpiration = true)]
Task<User> GetUserAsync(int id);

// 按用户区分缓存和高优先级
[Get("/api/profile")]
[Cache(300, VaryByUser = true, Priority = CachePriority.High)]
Task<Profile> GetProfileAsync();

// 参数作为表单内容
[Post("/api/login")]
Task<LoginResult> LoginAsync([FormContent] LoginRequest request);

// 类级别标记
[FormContent]
public class LoginRequest
{
    public string Username { get; set; }
    public string Password { get; set; }
}

[GenerateEventHandler(EventType = "message")]
public class MessageEventHandler : IEventHandler
{
    public Task HandleAsync(EventContext context)
    {
        // 处理消息事件
        return Task.CompletedTask;
    }
}

// 参数作为请求头
[Get("/api/users")]
Task<List<User>> GetUsersAsync([Header("X-API-Key")] string apiKey);

// 方法级别添加固定请求头
[Get("/api/users")]
[Header("Accept", "application/json")]
Task<List<User>> GetUsersAsync();

// 使用别名和替换模式
[Post("/api/data")]
Task SendDataAsync([Header("Authorization", Replace = true)] string auth);

// GUID 格式化
[Header("X-Request-Id", FormatString = "N")]

// 日期格式化
[Header("X-Timestamp", FormatString = "yyyy-MM-ddTHH:mm:ssZ")]

[HttpClientApi]
[Header("Accept", "application/json")]
[HeaderMerge(HeaderMergeMode.Replace)]
public interface IUserApi
{
    [Get("/api/users")]
    [Header("Accept", "text/plain")]
    Task<string> GetUsersAsTextAsync();
    // 方法级 Accept: text/plain 替换接口级 Accept: application/json
}

member.example:
定义 HTTP API 接口：

[HttpClientApi]
public interface IUserApi
{
    [Get("/api/users/{id}")]
    Task<User> GetUserAsync(int id);

    [Post("/api/users")]
    Task<User> CreateUserAsync([Body] User user);
}


注册和使用：

// 注册
builder.Services.AddMudHttpClient<IUserApi>("UserApi", "https://api.example.com");

// 使用
var userApi = serviceProvider.GetRequiredService<IUserApi>();
var user = await userApi.GetUserAsync(123);

example.code:
[HttpClientApi]
public interface IUserApi
{
    // 这个方法会被自动生成实现
    [Get("/api/users/{id}")]
    Task<User> GetUserAsync(int id);

    // 这个方法会被忽略，需要手动实现
    [IgnoreGenerator]
    Task<User> GetSpecialUserAsync(int id);
}

[HttpClientApi]
[InterfacePath("tenantId", "default-tenant")]
public interface IUserApi
{
    [Get("/api/tenants/{tenantId}/users/{userId}")]
    Task<User> GetUserAsync(int userId);
    // 实际请求: /api/tenants/default-tenant/users/123
}

[HttpClientApi]
[InterfaceQuery("api_version", "2.0")]
[InterfaceQuery("client_id", "my-app")]
public interface IUserApi
{
    [Get("/api/users/{id}")]
    Task<User> GetUserAsync(int id);
    // 实际请求: /api/users/1?api_version=2.0&client_id=my-app
}

[Get("/api/users/{id}")]
Task<User> GetUserAsync(int id);

[Get("/api/users")]
Task<List<User>> GetAllUsersAsync([Query] string? keyword = null);

[Post("/api/users")]
Task<User> CreateUserAsync([Body] User user);

[Post("/api/login")]
Task<LoginResult> LoginAsync([Body] LoginRequest request);

[Get("/api/users/{id}")]
Task<User> GetUserAsync([Path] int id);

// 使用格式化字符串
[Get("/api/reports/{reportDate}")]
Task<Report> GetReportAsync([Path(FormatString = "yyyy-MM-dd")] DateTime reportDate);

// 自定义占位符名称
[Get("/api/users/{userId}")]
Task<User> GetUserAsync([Path(Name = "userId")] int id);

// 禁用 URL 编码（用于传递包含 / 的路径）
[Get("/api/resource/{path}")]
Task GetResourceAsync([Path(UrlEncode = false)] string path);

// 日期格式化
[Path(FormatString = "yyyy-MM-dd")]

// 数字格式化
[Path(FormatString = "D5")]

// GUID 格式化
[Path(FormatString = "N")]

// 传递包含 / 的路径
[Get("/api/resource/{path}")]
Task GetResourceAsync([Path(UrlEncode = false)] string path);

// 调用代码
await api.GetResourceAsync("folder/subfolder/file.txt");
// 实际请求: /api/resource/folder/subfolder/file.txt

// 参数作为查询字符串
[Get("/api/users")]
Task<List<User>> GetUsersAsync([Query] string? keyword, [Query] int page = 1);

// 自定义参数名称
[Get("/api/users")]
Task<List<User>> GetUsersAsync([Query("page_size")] int pageSize);

// 方法级别添加固定查询参数
[Get("/api/users")]
[Query("status", "active")]
Task<List<User>> GetActiveUsersAsync();

// 使用别名
[Get("/api/users")]
Task<List<User>> SearchAsync([Query("q", AliasAs = "keyword")] string search);

public class SearchCriteria
{
    public string? Keyword { get; set; }
    public int Page { get; set; }
    public int PageSize { get; set; }
}

[Get("/api/search")]
Task<SearchResult> SearchAsync([QueryMap] SearchCriteria criteria);

// 调用: api.SearchAsync(new SearchCriteria { Keyword = "test", Page = 1, PageSize = 10 });
// 生成: /api/search?Keyword=test&Page=1&PageSize=10

[Get("/api/search")]
Task<SearchResult> SearchAsync([RawQueryString] string queryString);

// 调用: api.SearchAsync("keyword=test&page=1");
// 生成: /api/search?keyword=test&page=1

public class LoginRequest
{
    public string Username { get; set; }

    [SensitiveData(MaskMode = SensitiveDataMaskMode.Hide)]
    public string Password { get; set; }
}

public class PaymentInfo
{
    [SensitiveData(MaskMode = SensitiveDataMaskMode.Mask, PrefixLength = 4, SuffixLength = 4)]
    public string CardNumber { get; set; }
}

[HttpClientApi]
[SerializationMethod(SerializationMethod.Xml)]
public interface IXmlApi
{
    [Post("/api/data")]
    Task SendDataAsync([Body] DataModel data);
    // 使用 XML 序列化请求体

    [Post("/api/json-data")]
    [SerializationMethod(SerializationMethod.Json)]
    Task SendJsonDataAsync([Body] DataModel data);
    // 方法级覆盖，使用 JSON 序列化
}

// 接口级别使用令牌（默认 Header 模式）
[HttpClientApi]
[Token]
public interface ISecureApi
{
    [Get("/api/secure")]
    Task<SecureData> GetSecureDataAsync();
}

// 方法级别使用用户令牌和作用域
[Get("/api/user/profile")]
[Token("UserAccessToken", Scopes = "user:read")]
Task<Profile> GetProfileAsync();

// 自定义令牌名称和查询参数模式
[Get("/api/data")]
[Token("ApiKey", InjectionMode = TokenInjectionMode.Query, Name = "access_token")]
Task<Data> GetDataAsync();

// 基本文件上传
[Post("/api/upload")]
Task<UploadResult> UploadAsync([Upload] IFormFile file);

// 自定义字段名和文件名
[Post("/api/upload")]
Task<UploadResult> UploadAsync(
    [Upload(FieldName = "document", FileName = "report.pdf")] IFormFile file);

// 指定内容类型
[Post("/api/upload")]
Task<UploadResult> UploadImageAsync(
    [Upload(ContentType = "image/png")] IFormFile image);
